class Portfolio{static#build(data){const content=document.getElementById("content");data.forEach(category=>{const container=document.createElement("div");container.classList.add("category");if(category.title){const div=document.createElement("div");div.classList.add("category-title");Object.keys(category.title).forEach(local=>{const span=document.createElement("span");span.classList.add("localized");span.lang=local;span.innerHTML=category.title[local];div.appendChild(span);});container.appendChild(div);}category.projects.forEach(project=>{const card=document.createElement("div");card.classList.add("card","collapsed","item","collapsable");function __collapse(card){card.classList.remove("expanded");card.classList.add("collapsed");}function __expand(card){for(const other of content.getElementsByClassName("card")){__collapse(other);}card.classList.remove("collapsed");card.classList.add("expanded","border");}{{const div=document.createElement("div");div.classList.add("card-title","center");Object.keys(project.title).forEach(local=>{const span=document.createElement("span");span.classList.add("localized");span.lang=local;span.innerHTML=project.title[local];div.appendChild(span);});card.appendChild(div);}{const div=document.createElement("div");div.classList.add("card-description");Object.keys(project.description).forEach(local=>{const span=document.createElement("p");span.classList.add("localized");span.lang=local;span.innerHTML=project.description[local].replaceAll("&thinsp;","<span class=\"thinsp\"></span>");div.appendChild(span);});card.appendChild(div);}if(project.tech){const div=document.createElement("div");div.classList.add("card-tech");project.tech.forEach(tech=>{const block=document.createElement("div");block.classList.add("block-tech");const a=document.createElement("a");a.classList.add("tech","nowrap","frame");a.innerHTML=tech[0];a.href=tech[1];a.target="_blank";block.appendChild(a);div.appendChild(block);});card.appendChild(div);}["website","github","pdf"].forEach(key=>{if(project[key]){const div=document.createElement("div");div.classList.add("external","expanded");const span=document.createElement("span");span.classList.add("link","nowrap");span.innerHTML=key;const a=document.createElement("a");a.href=project[key];a.target="_blank";a.appendChild(span);const icon=document.createElement("span");icon.classList.add("open","nowrap");{const span=document.createElement("span");span.classList.add("localized");span.lang="en";span.innerHTML="[open]";icon.appendChild(span);}{const span=document.createElement("span");span.classList.add("localized");span.lang="de";span.innerHTML="[öffnen]";icon.appendChild(span);}a.appendChild(icon);div.appendChild(a);card.appendChild(div);}});{const div=document.createElement("div");div.classList.add("expand","collapsed","right");{const span=document.createElement("span");span.classList.add("localized","nowrap");span.lang="en";span.innerHTML="[expand]";div.appendChild(span);}{const span=document.createElement("span");span.classList.add("localized","nowrap");span.lang="de";span.innerHTML="[ausklappen]";div.appendChild(span);}card.appendChild(div);}{const div=document.createElement("div");div.classList.add("collapse","expanded","right");{const span=document.createElement("span");span.classList.add("localized");span.lang="en";span.innerHTML="[close]";span.addEventListener("click",event=>{__collapse(card);event.stopPropagation();});div.appendChild(span);}{const span=document.createElement("span");span.classList.add("localized");span.lang="de";span.innerHTML="[einklappen]";span.addEventListener("click",event=>{__collapse(card);event.stopPropagation();});div.appendChild(span);}card.appendChild(div);}}card.addEventListener("click",()=>{__expand(card);});container.appendChild(card);});content.appendChild(container);});}static build(){fetch("json/portfolio.min.json").then(response=>response.json()).then(data=>{Portfolio.#build(data.content);}).then(()=>{switch_lang(window.lang);}).catch(console.error);}}